// ============================================================
// SINGLE CODE NODE: Fetch all stocks, calculate indicators
// Uses this.helpers.httpRequest which IS available in n8n
// FIXED: Added &events=div to get dividend data
// ============================================================

var usStocks = [
  'AAPL','MSFT','AMZN','GOOGL','META','NVDA','TSLA','BRK-B',
